combobox_labeled_RMC.script:
function onInit()
	super.onInit();
	
	Module.addEventHandler("onModuleLoad", self.ModuleLoadUnload);
	Module.addEventHandler("onModuleUnload", self.ModuleLoadUnload);
	self.ModuleLoadUnload();
end
function ModuleLoadUnload()
	self.getProfessionLink();
	addItems(Rules_Professions.List());
end
function onValueChanged()
	self.getProfessionLink();
end
function getProfessionLink()
	local sCharNode = DB.getPath(window.getDatabaseNode());
	Rules_Professions.SetProfessionLink(getValue(), sCharNode);
end

linkfield.script:
function onInit()
	onValueChanged();
end
function onValueChanged()
	if isEmpty() then
		setVisible(false);
	else
		setVisible(true);
	end
	local _, sProfessionNodeName = getValue();
	local nodeProfession = DB.findNode(sProfessionNodeName);
	local sProfessionRealm = DB.getValue(nodeProfession, "realm", "");
	if sProfessionNodeName and not nodeProfession then
		local nLoc = string.find(sProfessionNodeName, "@");
		if nLoc then
			local sModule = string.sub(sProfessionNodeName, nLoc + 1);
			Module.activate(sModule);
		end
	end
	if sProfessionRealm ~= "Pick One" and sProfessionRealm ~= "" then
		DB.setValue(window.getDatabaseNode(), "realm", "string", sProfessionRealm);
	end
end
